mapper.select:
SELECT oa.*, ic.contract_code, bm.merchant_name, bs.shop_code FROM inv_opening_approval oa LEFT JOIN inv_lease_contract ic ON ic.id = oa.contract_id AND ic.is_deleted = 0 LEFT JOIN biz_merchant bm ON bm.id = oa.merchant_id AND bm.is_deleted = 0 LEFT JOIN biz_shop bs ON bs.id = oa.shop_id AND bs.is_deleted = 0 WHERE oa.is_deleted = 0
AND oa.project_id = #{projectId}
AND oa.status = #{status}
AND oa.contract_id = #{contractId}
ORDER BY oa.created_at DESC
